/// Compute SHA-256 of the given bytes, returning raw digest bytes.
pub fn sha256_bytes(data: &[u8]) -> Vec<u8>

pub fn sha256_bytes(data: &[u8]) -> Vec<u8> {
    let mut hasher = Sha256::new();
    hasher.update(data);
    hasher.finalize().to_vec()
}

