) -> Result<Json<serde_json::Value>, MimirError>

pub async fn list_sprints(
    State(state): State<Arc<AppState>>,
    Json(body): Json<SprintListRequest>,
) -> Result<Json<serde_json::Value>, MimirError> {
    let query_text = body
        .project
        .as_deref()
        .map(|p| format!("{p} sprint history"))
        .unwrap_or_else(|| "sprint history".to_string());
