            .await
            .map_err(|e| MimirError::Internal(format!("embed task panicked: {e}")))?
            .map_err(|e| MimirError::Internal(format!("embedder error: {e}")))?;

    let results = state
        .vectors
        .search("sprints", embedding, limit as u64)
        .await
        .map_err(MimirError::Store)?;

