        sdr::to_bytes(&query_sdr)
            .iter()
            .map(|b| format!("{b:02x}"))
            .collect::<String>(),
    );
    let response = RecallResponse {
        events,
        core_events,
        query_sdr_hex,
    };
    Ok((StatusCode::OK, Json(response)))
}

