pub fn from_bytes(bytes: &[u8]) -> Sdr {
    assert!(
        bytes.len() >= SDR_WORDS * 8,
        "need at least {} bytes, got {}",
        SDR_WORDS * 8,
        bytes.len()
    );
    let mut sdr = ZERO;
    for (i, chunk) in bytes.chunks_exact(8).take(SDR_WORDS).enumerate() {
