/// Execute hybrid search: embed query, run vector + BM25 in parallel,
/// fuse with RRF, batch-fetch full chunks from PostgreSQL, and return
/// ranked results.
///
/// This function owns the complete search pipeline. No other Muninn module
/// touches the database, vector store, or embedder.
///
/// Tracing spans are emitted for:
/// - Full function wall-clock time (excluding caller's embedding measurement)
/// - Individual parallel search legs
/// - RRF fusion
/// - Batch chunk fetch
pub async fn hybrid_search(
    state: &AppState,
    query: &str,
    limit: usize,
    languages: Option<&[String]>,
) -> Result<Vec<SearchResult>, MuninnError>

pub async fn hybrid_search(
    state: &AppState,
    query: &str,
    limit: usize,
    languages: Option<&[String]>,
) -> Result<Vec<SearchResult>, MuninnError> {
    let span = tracing::info_span!("hybrid_search", query = %query, limit = limit);
    let _enter = span.enter();

    // --- Step 1: Embed the query text ---
    let embedding_start = std::time::Instant::now();
    let query_embedding = state.embedder.embed_single(query).await?;
    tracing::debug!(elapsed_ms = embedding_start.elapsed().as_millis(), "query embedded");

    // Candidate count: fetch 3x limit from each backend to give RRF enough overlap.
    let candidate_limit = limit * 3;

    // --- Step 2: Run vector search and BM25 search in parallel ---
    let search_start = std::time::Instant::now();

    let qdrant_timed = async {
        let qdrant_start = std::time::Instant::now();
        let result = state
            .vectors
            .search("code_chunks", query_embedding, candidate_limit as u64)
            .await;
        crate::metrics::record_qdrant_duration("search", qdrant_start.elapsed().as_secs_f64());
        result
    };

    let (vector_result, bm25_result) = tokio::join!(
        qdrant_timed,
        search_bm25(&state.pool, query, candidate_limit, languages),
    );

    let vector_results = vector_result?;
    let bm25_results = bm25_result?;

    tracing::debug!(
        elapsed_ms = search_start.elapsed().as_millis(),
        vector_hits = vector_results.len(),
        bm25_hits = bm25_results.len(),
        "parallel search complete"
    );

    // --- Step 3: Fuse results with Reciprocal Rank Fusion ---
    let fusion_start = std::time::Instant::now();
    let fused = reciprocal_rank_fusion(&vector_results, &bm25_results, state.search_config.rrf_k);
    tracing::debug!(
        elapsed_us = fusion_start.elapsed().as_micros(),
        fused_candidates = fused.len(),
        "rrf fusion complete"
    );

    // --- Step 4: Take top `limit` candidates ---
    let top: Vec<(Uuid, f64)> = fused.into_iter().take(limit).collect();
    if top.is_empty() {
        tracing::debug!("no candidates after fusion");
        return Ok(vec![]);
    }

    // --- Step 5: Batch fetch full chunks from PostgreSQL ---
    let ids: Vec<Uuid> = top.iter().map(|(id, _)| *id).collect();

    let fetch_start = std::time::Instant::now();
    let chunks = get_chunks_by_ids(&state.pool, &ids).await?;
    tracing::debug!(
        elapsed_ms = fetch_start.elapsed().as_millis(),
        fetched = chunks.len(),
        requested = ids.len(),
        "batch chunk fetch complete"
    );

    // Build a lookup map: UUID -> CodeChunk (O(n) scan is fine for n <= 50).
    let chunk_map: std::collections::HashMap<Uuid, ygg_domain::chunk::CodeChunk> =
        chunks.into_iter().map(|c| (c.id, c)).collect();

    // --- Step 6: Assemble SearchResult vec preserving fused rank order ---
    let mut results = Vec::with_capacity(top.len());
    for (id, rrf_score) in &top {
        match chunk_map.get(id) {
            Some(chunk) => {
                results.push(SearchResult {
                    chunk: chunk.clone(),
                    score: *rrf_score,
                    source: SearchSource::Fused,
                });
            }
            None => {
                // Stale Qdrant point: the chunk was deleted from PostgreSQL after Qdrant
                // returned it. This is a benign race during Huginn re-indexing — skip it.
                tracing::warn!(chunk_id = %id, "stale qdrant id: chunk not found in postgresql, skipping");
            }
        }
    }

    tracing::info!(
        results = results.len(),
        "hybrid search complete"
    );

    Ok(results)
}

Implement the following Rust function for Yggdrasil:

/// Pack a session's history + RAG into a messages array that fits the budget.
    ///
    /// Returns the assembled message array ready for the LLM. The caller should
    /// NOT add a separate system prompt — it's already included in the output.
    ///
    /// Priority order (highest to lowest):
    ///   1. System prompt
    ///   2. Session summary (rolling compressed history)
    ///   3. Recent history (last 8 messages)
    ///   4. RAG code context
    ///   5. Previous project sessions (cross-window context, capped 500 tokens)
    ///   6. Older history turns (fill remaining space)
pub fn pack(
        &self,
        session: &ConversationSession,
        rag_context: Option<&str>,
        system_prompt: &str,
        previous_sessions: Option<&str>,
    ) -> Vec<ChatMessage>

pub fn pack(
        &self,
        session: &ConversationSession,
        rag_context: Option<&str>,
        system_prompt: &str,
        previous_sessions: Option<&str>,
    ) -> Vec<ChatMessage> {
        let budget = self.available();
        let mut used: usize = 0;
        let mut output: Vec<ChatMessage> = Vec::new();

        // ── 1. System prompt (always) ────────────────────────────────
        let system_tokens = system_prompt.len() / 4;
        used += system_tokens;
        output.push(ChatMessage::new(Role::System, system_prompt));

        // ── 2. Session summary (if exists) ───────────────────────────
        if let Some(ref summary) = session.summary {
            let summary_tokens = summary.len() / 4;
            if used + summary_tokens < budget {
                used += summary_tokens;
                output.push(ChatMessage::new(Role::System, format!("Summary of earlier conversation:\n{summary}")));
            }
        }

        // ── 3. Recent history (last 4 turn pairs = 8 messages) ───────
        // These are always included if they fit.
        let recent_count = session.messages.len().min(8);
        let recent_start = session.messages.len().saturating_sub(recent_count);
        let recent = &session.messages[recent_start..];

        let mut recent_tokens: usize = 0;
        let mut recent_msgs: Vec<ChatMessage> = Vec::new();
        for msg in recent {
            recent_tokens += msg.tokens_estimate;
            recent_msgs.push(ChatMessage::new(parse_role(&msg.role), &msg.content));
        }

        // ── 4. RAG code context ──────────────────────────────────────
        // Inserted between system prompt and history as a system message.
        if let Some(rag) = rag_context {
            let rag_tokens = rag.len() / 4;
            if used + rag_tokens + recent_tokens < budget {
                used += rag_tokens;
                output.push(ChatMessage::new(Role::System, rag));
            }
            // If RAG doesn't fit, skip it — recent history is more important.
        }

        // ── 5. Previous project sessions (cross-window context) ──────
        // Injected as a system message, capped at 500 tokens. Lowest priority
        // above older history — dropped silently if budget is tight.
        const PREV_SESSIONS_TOKEN_CAP: usize = 500;
        if let Some(prev) = previous_sessions {
            let prev_tokens = prev.len() / 4;
            let capped_tokens = prev_tokens.min(PREV_SESSIONS_TOKEN_CAP);
            if used + capped_tokens + recent_tokens < budget {
                used += capped_tokens;
                // Truncate to token cap if needed.
                let content = if prev_tokens > PREV_SESSIONS_TOKEN_CAP {
                    let char_limit = PREV_SESSIONS_TOKEN_CAP * 4;
                    &prev[..prev.len().min(char_limit)]
                } else {
                    prev
                };
                output.push(ChatMessage::new(Role::System, content));
            }
        }

        // ── 6. Older history turns (fill remaining space) ────────────
        let older = &session.messages[..recent_start];
        for msg in older {
            if used + msg.tokens_estimate + recent_tokens >= budget {
                break;
            }
            used += msg.tokens_estimate;
            output.push(ChatMessage::new(parse_role(&msg.role), &msg.content));
        }

        // ── 6. Append recent history ─────────────────────────────────
        // Recent messages go last (closest to the generation point).
        used += recent_tokens;
        let _ = used; // suppress unused warning
        output.extend(recent_msgs);

        output
    }

