                let data_inner = data_obj
                    .entry("data")
                    .or_insert_with(|| serde_json::json!({}));
                if let Some(inner_obj) = data_inner.as_object_mut() {
                    inner_obj.insert(
                        "image".to_string(),
                        serde_json::Value::String(image.clone()),
                    );
                }
            }

            if !notification.actions.is_empty() {
                let data_inner = data_obj
                    .entry("data")
                    .or_insert_with(|| serde_json::json!({}));
                if let Some(inner_obj) = data_inner.as_object_mut() {
                    inner_obj.insert(
