pub async fn bump_version(
    pool: &PgPool,
    component: &str,
    bump_type: &str,
) -> Result<String, StoreError> {
    let current = get_version(pool, component)
        .await?
        .map(|v| v.version)
        .unwrap_or_else(|| "0.0.0".to_string());

    let parts: Vec<&str> = current.split('.').collect();
    if parts.len() != 3 {
        return Err(StoreError::Query(format!(
            "invalid semver for component '{component}': {current}"
        )));
    }

    let major: u32 = parts[0]
        .parse()
        .map_err(|_| StoreError::Query(format!("invalid semver: {current}")))?;
    let minor: u32 = parts[1]
        .parse()
        .map_err(|_| StoreError::Query(format!("invalid semver: {current}")))?;
    let patch: u32 = parts[2]
        .parse()
        .map_err(|_| StoreError::Query(format!("invalid semver: {current}")))?;

    let new_version = match bump_type {
        "patch" => format!("{major}.{minor}.{}", patch + 1),
        "minor" => format!("{major}.{}.0", minor + 1),
        _ => {
            return Err(StoreError::Query(format!(
                "invalid bump_type '{bump_type}': expected 'minor' or 'patch'"
            )));
        }
    };

    set_version(pool, component, &new_version).await?;
    Ok(new_version)
}

pub async fn link(
    pool: &PgPool,
    source_id: Uuid,
    target_id: Uuid,
    relation: &str,
    weight: f32,
    metadata: Option<serde_json::Value>,
) -> Result<Uuid, StoreError> {
    let meta = metadata.unwrap_or(serde_json::json!({}));

    let id: (Uuid,) = sqlx::query_as(
        "INSERT INTO yggdrasil.engram_edges (source_id, target_id, relation, weight, metadata)
         VALUES ($1, $2, $3, $4, $5)
         RETURNING id",
    )
    .bind(source_id)
    .bind(target_id)
    .bind(relation)
    .bind(weight)
    .bind(&meta)
    .fetch_one(pool)
    .await
    .map_err(|e| {
        if e.to_string().contains("unique_edge") || e.to_string().contains("duplicate") {
            StoreError::Duplicate(format!(
                "edge already exists: {} --[{}]--> {}",
                source_id, relation, target_id
            ))
        } else {
            StoreError::Query(e.to_string())
        }
    })?;

    Ok(id.0)
}

