pub async fn neighbors(
    pool: &PgPool,
    engram_id: Uuid,
    direction: Direction,
    relation: Option<&str>,
    limit: u32,
) -> Result<Vec<Edge>, StoreError> {
    let (sql, bind_relation) = match direction {
        Direction::Outgoing => {
            if relation.is_some() {
                (
                    "SELECT id, source_id, target_id, relation, weight, metadata, created_at
                     FROM yggdrasil.engram_edges
                     WHERE source_id = $1 AND relation = $2
                     ORDER BY weight DESC, created_at DESC
                     LIMIT $3",
                    true,
                )
            } else {
                (
                    "SELECT id, source_id, target_id, relation, weight, metadata, created_at
                     FROM yggdrasil.engram_edges
                     WHERE source_id = $1
                     ORDER BY weight DESC, created_at DESC
                     LIMIT $2",
                    false,
                )
            }
        }
        Direction::Incoming => {
            if relation.is_some() {
                (
                    "SELECT id, source_id, target_id, relation, weight, metadata, created_at
                     FROM yggdrasil.engram_edges
                     WHERE target_id = $1 AND relation = $2
                     ORDER BY weight DESC, created_at DESC
                     LIMIT $3",
                    true,
                )
            } else {
                (
                    "SELECT id, source_id, target_id, relation, weight, metadata, created_at
                     FROM yggdrasil.engram_edges
                     WHERE target_id = $1
                     ORDER BY weight DESC, created_at DESC
                     LIMIT $2",
                    false,
                )
            }
        }
        Direction::Both => {
            if relation.is_some() {
                (
                    "SELECT id, source_id, target_id, relation, weight, metadata, created_at
                     FROM yggdrasil.engram_edges
                     WHERE (source_id = $1 OR target_id = $1) AND relation = $2
                     ORDER BY weight DESC, created_at DESC
                     LIMIT $3",
                    true,
                )
            } else {
                (
                    "SELECT id, source_id, target_id, relation, weight, metadata, created_at
                     FROM yggdrasil.engram_edges
                     WHERE (source_id = $1 OR target_id = $1)
                     ORDER BY weight DESC, created_at DESC
                     LIMIT $2",
                    false,
                )
            }
        }
    };

    let rows = if bind_relation {
        sqlx::query_as::<_, EdgeRow>(sql)
            .bind(engram_id)
            .bind(relation.unwrap_or(""))
            .bind(limit as i64)
            .fetch_all(pool)
            .await
    } else {
        sqlx::query_as::<_, EdgeRow>(sql)
            .bind(engram_id)
            .bind(limit as i64)
            .fetch_all(pool)
            .await
    };

    rows.map(|rs| rs.into_iter().map(Into::into).collect())
        .map_err(|e| StoreError::Query(e.to_string()))
}

