    /// Returns the best match above the threshold, or None.
pub fn match_command(&self, audio: &[f32], mel: &MelSpectrogram) -> Option<&SdrCommand>

pub fn match_command(&self, audio: &[f32], mel: &MelSpectrogram) -> Option<&SdrCommand> {
        if self.commands.is_empty() {
            return None;
