pub struct RecallQuery {
    pub text: String,
    #[serde(default = "default_query_limit")]
    pub limit: usize,
    /// When true, populate `cause` and `effect` on returned EngramEvents.
    /// Backward-compatible: callers that omit this field get the original metadata-only response.
    #[serde(default)]
    pub include_text: Option<bool>,
    /// Scope search to a specific project. None = search everything.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub project: Option<String>,
    /// When true (default), also include global-scope engrams in results.
    #[serde(default = "default_include_global")]
    pub include_global: bool,
}

/// Response from event-based recall.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RecallResponse {
    pub events: Vec<EngramEvent>,
    pub core_events: Vec<EngramEvent>,
    /// Hex-encoded 256-bit SDR of the query text (optional, for session drift tracking).
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub query_sdr_hex: Option<String>,
}

/// Request for the autonomous memory ingest endpoint (`POST /api/v1/auto-ingest`).
///
/// Hook scripts send this after every Edit/Write/Bash tool invocation.
/// Mimir embeds the content and matches against dense template embeddings via
/// cosine similarity. Stores an engram only when the best match exceeds the threshold.
#[derive(Debug, Serialize, Deserialize)]
pub struct AutoIngestRequest {
    /// Text to classify and potentially store.
    pub content: String,
    /// Originating tool identifier, e.g. "Edit", "Write", "Bash".
    pub source: String,
    /// "pre_tool" or "post_tool".
    pub event_type: String,
    /// Hostname of the workstation that generated this event.
    pub workstation: String,
    /// File being edited/written, if applicable.
    #[serde(default)]
    pub file_path: Option<String>,
    /// Project identifier for scoping, e.g. "yggdrasil".
    #[serde(default)]
    pub project: Option<String>,
}

/// Response from the autonomous memory ingest endpoint.
#[derive(Debug, Serialize, Deserialize)]
pub struct AutoIngestResponse {
    /// Whether an engram was created.
    pub stored: bool,
    /// UUID of the created engram, if stored.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub engram_id: Option<Uuid>,
    /// Name of the insight template that matched, if any.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub matched_template: Option<String>,
    /// Cosine similarity score against the matched template.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub similarity: Option<f64>,
    /// Why the engram was not stored, e.g. "below_threshold", "duplicate", "cooldown".
    #[serde(skip_serializing_if = "Option::is_none")]
    pub skipped_reason: Option<String>,
}

/// Cluster-level configuration for node mesh networking.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ClusterConfig {
    /// This node's identity within the mesh.
    pub node: NodeIdentity,
    /// How nodes discover each other.
    #[serde(default)]
    pub discovery: DiscoveryConfig,
    /// Heartbeat and timeout settings.
    #[serde(default)]
    pub heartbeat: HeartbeatConfig,
    /// Gate policy rules for inter-node tool access.
    #[serde(default)]
    pub gate: GateConfig,
}

/// This node's identity and capabilities.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NodeIdentity {
    /// Unique node name (e.g. "munin", "hugin", "thor").
    pub name: String,
    /// Human-readable role description.
    #[serde(default)]
    pub role: String,
    /// Services hosted on this node (e.g. ["odin", "mimir"]).
    #[serde(default)]
    pub services: Vec<String>,
    /// Address this node advertises to the mesh (e.g. "192.168.1.100").
    pub advertise_addr: String,
    /// Port for mesh API (default 9100).
    #[serde(default = "default_mesh_port")]
    pub mesh_port: u16,
}

/// Discovery mechanism configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DiscoveryConfig {
    /// Discovery mode: "mdns" or "static".
    #[serde(default = "default_discovery_mode")]
    pub mode: DiscoveryMode,
    /// Static seed nodes (used when mode = "static" or as bootstrap for mDNS).
    #[serde(default)]
    pub seeds: Vec<SeedNode>,
    /// mDNS service name (default: "_yggdrasil._tcp.local").
    #[serde(default = "default_mdns_service")]
    pub mdns_service: String,
}

/// A statically configured seed node for bootstrap or static-only mode.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SeedNode {
    pub name: String,
    pub addr: String,
    pub port: u16,
}

/// Heartbeat configuration for mesh liveness detection.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HeartbeatConfig {
    /// Heartbeat interval in seconds (default 30).
    #[serde(default = "default_heartbeat_interval")]
    pub interval_secs: u64,
    /// Number of missed heartbeats before a node is considered offline (default 3).
    #[serde(default = "default_missed_threshold")]
    pub missed_threshold: u32,
}

/// Gate policy engine for controlling inter-node access.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GateConfig {
    /// Default policy when no rule matches (default: allow).
    #[serde(default = "default_gate_policy")]
    pub default_policy: GatePolicy,
    /// Deny rules evaluated in order. First match wins.
    #[serde(default)]
    pub rules: Vec<GateRule>,
}

/// A gate rule matching source/target node and tool name.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GateRule {
    /// Source node name pattern (glob, e.g. "*" or "thor").
    pub source: String,
    /// Target tool name pattern (glob, e.g. "ha_*" or "*").
    pub tool: String,
    /// Policy to apply when matched.
    pub policy: GatePolicy,
}

/// Runtime state of a node in the mesh.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NodeState {
    /// Node identity.
    pub identity: NodeIdentity,
    /// Current status.
    pub status: NodeStatus,
    /// Capabilities advertised by this node.
    pub capabilities: NodeCapabilities,
    /// Last successful heartbeat timestamp (Unix epoch seconds).
    pub last_heartbeat: u64,
    /// Mesh protocol version.
    pub version: String,
}

/// Capabilities a node advertises to the mesh.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NodeCapabilities {
    /// Services available on this node with their addresses.
    pub services: HashMap<String, ServiceEndpoint>,
    /// Whether this node has GPU compute available.
    #[serde(default)]
    pub has_gpu: bool,
    /// Energy policy for this node.
    #[serde(default)]
    pub energy_policy: Option<String>,
}

/// A service endpoint within a node.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ServiceEndpoint {
    /// HTTP address (e.g. "http://192.168.1.100:8080").
    pub url: String,
    /// Health check path (default: "/health").
    #[serde(default = "default_health_path")]
    pub health_path: String,
}

/// Mesh handshake request/response — exchanged on first contact.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MeshHello {
    pub node: NodeIdentity,
    pub capabilities: NodeCapabilities,
    pub version: String,
}

/// Mesh proxy request — routes a request through the mesh to a target node.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MeshProxyRequest {
    /// Source node initiating the request.
    pub source_node: String,
    /// Target service name on the receiving node.
    pub service: String,
    /// HTTP method (GET, POST, etc.).
    pub method: String,
    /// Path on the target service (e.g. "/api/v1/search").
    pub path: String,
    /// Optional request body (JSON string).
    #[serde(default)]
    pub body: Option<String>,
    /// Optional headers.
    #[serde(default)]
    pub headers: HashMap<String, String>,
}

/// Mesh proxy response.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MeshProxyResponse {
    pub status: u16,
    pub body: String,
    #[serde(default)]
    pub headers: HashMap<String, String>,
}

/// Heartbeat payload sent periodically between nodes.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Heartbeat {
    pub node_name: String,
    pub timestamp: u64,
    /// Current load (optional, for future routing decisions).
    #[serde(default)]
    pub load: Option<f64>,
}

/// Per-node energy configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NodeEnergyConfig {
    pub node_name: String,
    pub policy: EnergyPolicy,
    /// MAC address for Wake-on-LAN (required for on_demand/prioritized).
    #[serde(default)]
    pub wol_mac: Option<String>,
    /// Broadcast address for WoL (default: 255.255.255.255).
    #[serde(default = "default_broadcast")]
    pub wol_broadcast: String,
    /// Idle timeout in minutes before sleep (default: 30).
    #[serde(default = "default_idle_timeout")]
    pub idle_timeout_mins: u64,
    /// Proxmox API URL (if this node is a Proxmox VM/CT).
    #[serde(default)]
    pub proxmox_url: Option<String>,
    /// Proxmox node name (host) the VM runs on.
    #[serde(default)]
    pub proxmox_node: Option<String>,
    /// Proxmox VM ID (if managed via Proxmox).
    #[serde(default)]
    pub proxmox_vmid: Option<u32>,
}

/// Top-level energy configuration (loaded from configs/energy/config.json).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EnergyConfig {
    pub nodes: Vec<NodeEnergyConfig>,
}

/// Status of a Proxmox VM.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct VmStatus {
    pub vmid: u32,
    pub status: String, // "running", "stopped", etc.
}

/// Summary of a QEMU VM from the Proxmox node listing.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct VmInfo {
    pub vmid: u32,
    pub name: Option<String>,
    pub status: String,
}

/// Summary of an LXC container from the Proxmox node listing.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct ContainerInfo {
    pub vmid: u32,
    pub name: Option<String>,
    pub status: String,
}

/// Status of a Proxmox LXC container.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct ContainerStatus {
    pub vmid: u32,
    pub status: String,
}

/// An HA entity state.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EntityState {
    pub entity_id: String,
    pub state: String,
    #[serde(default)]
    pub attributes: serde_json::Value,
    #[serde(default)]
    pub last_changed: Option<String>,
}

/// Services available within a single HA domain (e.g., `light`, `switch`).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DomainServices {
    pub domain: String,
    pub services: HashMap<String, ServiceDef>,
}

/// Definition of a single HA service.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ServiceDef {
    #[serde(default)]
    pub name: Option<String>,
    #[serde(default)]
    pub description: Option<String>,
    #[serde(default)]
    pub fields: HashMap<String, serde_json::Value>,
}

/// Notification payload for mobile push via HA Companion App.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Notification {
    pub title: String,
    pub message: String,
    /// Optional notification priority: "high", "default", "low".
    #[serde(default)]
    pub priority: Option<String>,
    /// Optional notification channel (Android).
    #[serde(default)]
    pub channel: Option<String>,
    /// Optional image URL to include.
    #[serde(default)]
    pub image: Option<String>,
    /// Optional actions (interactive buttons).
    #[serde(default)]
    pub actions: Vec<NotificationAction>,
}

/// An interactive action button on a notification.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NotificationAction {
    pub action: String,
    pub title: String,
    #[serde(default)]
    pub uri: Option<String>,
}

/// Incoming webhook payload from Home Assistant automations.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WebhookPayload {
    /// The webhook trigger ID (matches HA automation trigger).
    #[serde(default)]
    pub trigger_id: Option<String>,
    /// Entity that triggered the webhook (if entity-based).
    #[serde(default)]
    pub entity_id: Option<String>,
    /// New state value (if state-change trigger).
    #[serde(default)]
    pub new_state: Option<String>,
    /// Old state value (if state-change trigger).
    #[serde(default)]
    pub old_state: Option<String>,
    /// Arbitrary data payload from the automation.
    #[serde(default)]
    pub data: serde_json::Value,
}

/// Response to send back to HA after processing a webhook.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WebhookResponse {
    pub status: String,
    #[serde(default)]
    pub message: Option<String>,
}

#[derive(Debug, Serialize, Deserialize)]
pub struct SyncState {
    pub config_version: String,
    pub last_sync: String,
    pub files: HashMap<String, String>,
}
